// String tipi
let greeting: string = 'Salam';
let message: string = "Dünya!";
let template: string = `Mesaj: ${greeting}, ${message}`;

console.log(template); // Mesaj: Salam, Dünya!
// greeting = 42; // Xəta: number string-ə təyin edilə bilməz

// Number tipi
let age: number = 25;
let price: number = 99.99;
let infinity: number = Infinity;

console.log(age, price, infinity); // 25, 99.99, Infinity
// age = 'yirmibeş'; // Xəta: string number-ə təyin edilə bilməz

// Boolean tipi
let isActive: boolean = true;
let hasAccess: boolean = false;

if (isActive) {
  console.log('İstifadəçi aktivdir');
} else {
  console.log('İstifadəçi aktiv deyil');
}
// isActive = 'true'; // Xəta: string boolean-a təyin edilə bilməz

// Null tipi
let userName: string | null = 'Ali';
userName = null;

console.log(userName); // null
// userName = 42; // Xəta: number nullable tipə uyğun deyil

// Undefined tipi
let value: string | undefined;
console.log(value); // undefined
value = 'Hello';
console.log(value); // Hello
// value = 42; // Xəta: number undefined tipə uyğun deyil

// Null və undefined fərqləri
let nullValue: string | null = null;
let undefinedValue: string | undefined;

console.log(nullValue); // null
console.log(undefinedValue); // undefined

// Void tipi
function logMessage(message: string): void {
  console.log(message);
}

logMessage('Salam, Dünya!'); // Salam, Dünya!
// return 42; // Xəta: void funksiya dəyər qaytara bilməz

// Praktik nümunə
interface User {
  name: string;
  age: number;
  isActive: boolean;
  email: string | null;
  lastLogin: string | undefined;
}

function displayUser(user: User): void {
  console.log(`Ad: ${user.name}`);
  console.log(`Yaş: ${user.age}`);
  console.log(`Aktiv: ${user.isActive}`);
  console.log(`Email: ${user.email ?? 'Yoxdur'}`);
  console.log(`Son giriş: ${user.lastLogin ?? 'Hələ giriş etməyib'}`);
}

let user: User = {
  name: 'Məmməd',
  age: 22,
  isActive: true,
  email: null,
  lastLogin: undefined,
};

displayUser(user);
// Çıxış:
// Ad: Məmməd
// Yaş: 22
// Aktiv: true
// Email: Yoxdur
// Son giriş: Hələ giriş etməyib

// Təhlükəsizlik nümunəsi
let userName: string | null = null;

if (userName !== null) {
  console.log(userName.toUpperCase());
} else {
  console.log('İstifadəçi adı yoxdur');
}
// Çıxış: İstifadəçi adı yoxdur

// Səhvə yol açan nümunə
let data: string = 'Hello';
// data = 42; // Xəta: number string-ə təyin edilə bilməz

let unsafe: any = 'Hello';
unsafe = 42;
console.log(unsafe); // 42 (təhlükəsiz deyil)

// Düzgün yol
let text: string = 'Hello';
console.log(text.toUpperCase()); // HELLO

// Real layihə ssenarisi
function processOrder(orderId: number, customerName: string, isPaid: boolean, discount: number | null): void {
  console.log(`Sifariş ID: ${orderId}`);
  console.log(`Müştəri: ${customerName}`);
  console.log(`Ödənilib: ${isPaid}`);
  console.log(`Endirim: ${discount ?? 'Yoxdur'}`);
}

processOrder(101, 'Ayşə', true, 10);
// Çıxış:
// Sifariş ID: 101
// Müştəri: Ayşə
// Ödənilib: true
// Endirim: 10

